import{_ as e,o as a,c as n,S as i}from"./chunks/framework.C6RQlTYc.js";const p=JSON.parse('{"title":"Attention（注意力机制）","description":"","frontmatter":{},"headers":[],"relativePath":"直击概念/17ai/s_ai_10-attention.md","filePath":"直击概念/17ai/s_ai_10-attention.md","lastUpdated":1778207238000}'),o={name:"直击概念/17ai/s_ai_10-attention.md"};function r(l,t,s,d,h,u){return a(),n("div",null,[...t[0]||(t[0]=[i('<h1 id="attention-注意力机制" tabindex="-1">Attention（注意力机制） <a class="header-anchor" href="#attention-注意力机制" aria-label="Permalink to &quot;Attention（注意力机制）&quot;">​</a></h1><h2 id="概念" tabindex="-1">概念 <a class="header-anchor" href="#概念" aria-label="Permalink to &quot;概念&quot;">​</a></h2><p>注意力机制（Attention Mechanism）是 Transformer 的核心组件，它让模型在处理每个 token 时能够<strong>动态地关注输入序列中的相关部分</strong>，而不是平等对待所有 token。</p><p>类比来说：人类阅读时不会逐字逐句地平等处理，而是对关键信息&quot;pay attention&quot;。Attention 机制赋予 AI 同样的能力。</p><h2 id="核心原理" tabindex="-1">核心原理 <a class="header-anchor" href="#核心原理" aria-label="Permalink to &quot;核心原理&quot;">​</a></h2><h3 id="scaled-dot-product-attention" tabindex="-1">Scaled Dot-Product Attention <a class="header-anchor" href="#scaled-dot-product-attention" aria-label="Permalink to &quot;Scaled Dot-Product Attention&quot;">​</a></h3><p>Transformer 的自注意力计算公式：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>Attention(Q, K, V) = softmax(QK^T / √d_k) · V</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>三个核心矩阵</strong>：</p><ul><li><strong>Q（Query，查询）</strong>：当前 token 想&quot;查询&quot;什么——我要找什么信息</li><li><strong>K（Key，键）</strong>：每个 token 的&quot;索引&quot;标签——我有什么信息可被查询</li><li><strong>V（Value，值）</strong>：每个 token 的&quot;内容&quot;——我实际携带的信息</li></ul><p><strong>计算步骤</strong>：</p><ol><li>计算 Q 和所有 K 的点积 → 得到注意力分数矩阵</li><li>除以 √d_k（缩放因子，防止梯度过小）</li><li>通过 Softmax 归一化为概率分布（注意力权重）</li><li>用权重对 V 做加权求和 → 得到当前 token 的上下文表示</li></ol><h3 id="multi-head-attention-多头注意力" tabindex="-1">Multi-Head Attention（多头注意力） <a class="header-anchor" href="#multi-head-attention-多头注意力" aria-label="Permalink to &quot;Multi-Head Attention（多头注意力）&quot;">​</a></h3><p>将 Q、K、V 通过不同的线性投影映射到多个子空间，在每个子空间独立计算 Attention，最后拼接。</p><p><strong>为什么需要多头</strong>：</p><ul><li>每个头可以学习<strong>不同类型的注意力模式</strong></li><li>有的头关注语法结构，有的关注语义关联，有的关注位置关系</li><li>多个头 = 从不同角度理解输入</li></ul><h3 id="cross-attention-vs-self-attention" tabindex="-1">Cross-Attention vs Self-Attention <a class="header-anchor" href="#cross-attention-vs-self-attention" aria-label="Permalink to &quot;Cross-Attention vs Self-Attention&quot;">​</a></h3><ul><li><strong>Self-Attention</strong>：Q、K、V 来自同一个序列，让序列内互相注意</li><li><strong>Cross-Attention</strong>：Q 来自当前序列，K、V 来自另一个序列（如 Encoder 的输出）</li></ul><h2 id="注意力机制的类型" tabindex="-1">注意力机制的类型 <a class="header-anchor" href="#注意力机制的类型" aria-label="Permalink to &quot;注意力机制的类型&quot;">​</a></h2><table><thead><tr><th>类型</th><th>计算范围</th><th>复杂度</th><th>用途</th></tr></thead><tbody><tr><td>全局注意力</td><td>全部 token</td><td>O(n²)</td><td>标准 Transformer</td></tr><tr><td>因果/掩码注意力</td><td>只看左边</td><td>O(n²)</td><td>GPT 等自回归模型</td></tr><tr><td>稀疏注意力</td><td>部分 token</td><td>O(n·log n)</td><td>长文本优化</td></tr><tr><td>滑动窗口注意力</td><td>固定窗口</td><td>O(n·w)</td><td>Mistral 等</td></tr><tr><td>Flash Attention</td><td>算法优化</td><td>O(n²) 更快</td><td>主流 LLM 标配</td></tr></tbody></table><h2 id="面试常问" tabindex="-1">面试常问 <a class="header-anchor" href="#面试常问" aria-label="Permalink to &quot;面试常问&quot;">​</a></h2><ul><li>Self-Attention 为什么需要 Q、K、V 三个矩阵？一个不行吗？</li><li>注意力分数的 softmax 缩放因子 √d_k 的作用是什么？</li><li>注意力机制的计算复杂度是多少？如何处理长文本？</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/1706.03762" target="_blank" rel="noreferrer">Attention Is All You Need</a></li><li><a href="https://jalammar.github.io/visualizing-neural-machine-translation-mechanics-of-seq2seq-models-with-attention/" target="_blank" rel="noreferrer">The Illustrated Attention</a></li></ul>',24)])])}const m=e(o,[["render",r]]);export{p as __pageData,m as default};
